import type { DatasetConfig } from './config.js';

/**
 * The dataset generated by the buildDataset function. This is exported and used
 * by the mock api to serve data.
 */
export type Dataset = Record<string, never>;
export type DatasetIndexes = Record<string, never>;

type DatasetBuildResult = {
  config: DatasetConfig;
  data: Dataset;
  indexes: DatasetIndexes;
};

/**
 * This starter implementation intentionally returns an empty dataset.
 * Replace it with your own domain-specific generators as your project takes shape.
 */
export function buildDataset(config: DatasetConfig): DatasetBuildResult {
  return {
    config,
    data: {},
    indexes: {},
  };
}
